class Solution {
    public int minFlipsMonoIncr(String s) {
        int flips = 0;
        int zeroCount = 0;
        for (char c : s.toCharArray()) {
            if (c == '0') {
                zeroCount++;
            }
            flips = Math.min(flips, zeroCount);
        }
        return flips;
    }
}
```
